// ─── Leaflet Map ──────────────────────────────────────────────────────────────
const map = L.map('map', {
  center: [22, 12],
  zoom: 2,
  minZoom: 2,
  maxZoom: 13,
  zoomControl: false,
  worldCopyJump: true,
  // Restrict vertical panning only — allow free horizontal wrap
  maxBounds: L.latLngBounds(L.latLng(-82, -100000), L.latLng(82, 100000)),
  maxBoundsViscosity: 1.0,
});

// ── Custom panes so the dark filter only hits the satellite layer ─────────────
// satellite pane: z 200 (below events), receives the CSS dark filter
map.createPane('satellite');
map.getPane('satellite').style.zIndex = 200;
map.getPane('satellite').className += ' leaflet-satellite-pane';

// borders pane: z 205 — above satellite, below event circles (overlayPane=400)
map.createPane('borders');
map.getPane('borders').style.zIndex = 205;
map.getPane('borders').style.pointerEvents = 'none';

// worldGlow pane: z 250 — above borders/tiles, below event circles (400)
map.createPane('worldGlowPane');
map.getPane('worldGlowPane').style.zIndex = 250;
map.getPane('worldGlowPane').style.pointerEvents = 'none';

// ── Base: ESRI World Imagery (satellite, darkened via CSS pane filter) ────────
// No country borders or labels — political territory is shown by PHASE_REGIONS.
L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}', {
  attribution: 'Tiles &copy; Esri',
  maxZoom: 19,
  pane: 'satellite',
}).addTo(map);
// Labels layer — country names, borders, and place names on transparent background
// Placed above the satellite pane (z=200) and region overlays (z=202), below event markers
L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/Reference/World_Boundaries_and_Places/MapServer/tile/{z}/{y}/{x}', {
  attribution: '',
  maxZoom: 19,
  pane: 'borders',
  opacity: 0.9,
}).addTo(map);
// Historical empire boundaries are rendered dynamically from the PHASE_REGIONS system.

// Zoom controls in bottom-right
L.control.zoom({ position: 'bottomright' }).addTo(map);

// ─── World-Glow system ────────────────────────────────────────────────────────
// Global-scale events (radius ≥ GLOBAL_RADIUS_THRESHOLD) skip the outer circle
// and instead tint the entire map with their category color at very low opacity.
const GLOBAL_RADIUS_THRESHOLD = 1_500_000;
const activeGlobalColors      = new Map(); // eventId → hex color

function _hexToRgb(hex) {
  const h = hex.replace('#', '');
  return [parseInt(h.slice(0,2),16), parseInt(h.slice(2,4),16), parseInt(h.slice(4,6),16)];
}

// World-spanning SVG rectangle — lives in the worldGlowPane (z 250)
const _worldGlowRect = L.rectangle(L.latLngBounds([[-85,-180],[85,180]]), {
  pane:        'worldGlowPane',
  color:       'none',
  fillColor:   '#ffffff',
  fillOpacity: 0,
  weight:      0,
  interactive: false,
  className:   'world-glow-rect',
}).addTo(map);

function updateWorldGlow() {
  // World-glow color cast is disabled — keep the rectangle fully transparent.
  const path = _worldGlowRect.getElement();
  if (path) path.style.fillOpacity = '0';
}

// ─── Helpers ──────────────────────────────────────────────────────────────────
function fmtYear(y) {
  if (y === null || isNaN(y)) return '';
  const abs = Math.abs(Math.round(y));
  return y < 0 ? `${abs} BCE` : `${abs} CE`;
}

// px: importance 1→16, 2→10, 3→7
function makeIcon(color, px = 10) {
  const wrap = Math.round(px * 4);
  return L.divIcon({
    className: '',
    html: `<div class="ev-wrap">
      <div class="ev-dot" style="width:${px}px;height:${px}px;background:${color};box-shadow:0 0 ${Math.round(px*0.9)}px ${color}bb;border-color:rgba(255,255,255,0.6)"></div>
      <div class="ev-pulse" style="width:${px}px;height:${px}px;background:${color}"></div>
    </div>`,
    iconSize:    [wrap, wrap],
    iconAnchor:  [wrap/2, wrap/2],
    popupAnchor: [0, -wrap/2],
  });
}

// ─── Fast ID lookup (O(1) instead of O(n) EVENTS.find everywhere) ─────────────
const EVENTS_BY_ID = new Map(EVENTS.map(e => [e.id, e]));

// ─── Importance tiers (1=world-changing, 2=significant, 3=supporting detail) ──
// Dot sizes:  tier1=16px  tier2=10px  tier3=7px
// Circle fill: tier1=0.22  tier2=0.14  tier3=0.08
const _IMP1 = new Set([
  'sumer','egyold','han_china','qin','fall_rome','black_death','printing_press',
  'columbus','reformation','industrial_rev','french_rev','american_rev',
  'napoleon_wars','russian_rev','ww1','ww2','holocaust','hiroshima',
  'alexander','fall_constantinople','ottoman_rise','soviet_collapse',
  'nuclear_arms_race','islamic_golden','mongol_sack_bg','atlantic_slave_trade',
  'genghis_death','covid19','dna_discovery','first_crusade','roman_peak',
]);
const _IMP3 = new Set([
  'verdun','somme','gallipoli','midway','el_alamein','dday','dunkirk',
  'invasion_poland','operation_barbarossa','pearl_harbor','stalingrad',
  'trafalgar','waterloo','marathon','thermopylae','salamis','gaugamela',
  'kadesh','lepanto','armada','boston_tea_party','bastille_fall',
  'reign_of_terror','pompeii','ain_jalut','conquest_aztec','suez_open',
  'wright_brothers','titanic','balkan_wars','berlin_airlift','cuban_missile',
  'jfk_assassinated','paris_attacks','dotcom_bust','great_barrier_reef',
  'katrina','haiti_quake','fukushima','battle_hastings','nuremberg_trials',
  'yom_kippur_war','nixon_china','camp_david','joan_of_arc','cortez_inca',
  'pelopo','roman_colosseum','olympia','council_nicaea','ain_jalut',
]);
function eventImportance(id) {
  if (_IMP1.has(id)) return 1;
  if (_IMP3.has(id)) return 3;
  return 2;
}
const _IMP_DOT_PX  = [16, 10, 7];
const _IMP_FILL_OP = [0.22, 0.14, 0.08];
const _IMP_WEIGHT  = [2.5, 1.5, 1.2];

// ─── Layer Management ─────────────────────────────────────────────────────────
const activeLayers   = new Map(); // id -> {circle, marker, lines:[]}
let causalLinkLayers = [];        // temporary lines drawn when an event is selected

// ── Connection highlight state ─────────────────────────────────────────────────
// Tracks which event is currently selected so clearCausalLinks can restore styles
let _connectionActiveId = null;

// Return the correct base circle style for a layer given current app state.
// Used by both initial styling and mouseout to avoid stale overrides.
function _baseCircleStyle(id) {
  const ev  = EVENTS_BY_ID.get(id);
  const c   = ev ? (DOT_COLORS[ev.color]?.dot || '#aaaaff') : '#aaaaff';
  const imp = eventImportance(id);
  return {
    color: c, fillColor: c,
    weight: _IMP_WEIGHT[imp - 1],
    opacity: 0.75,
    fillOpacity: _IMP_FILL_OP[imp - 1],
  };
}

function drawCausalLinks(evt) {
  clearCausalLinks();
  if (!evt.lat && !evt.lon) return;
  _connectionActiveId = evt.id;

  const causeLinks  = CAUSAL_LINKS.filter(l => l.effect === evt.id);
  const effectLinks = CAUSAL_LINKS.filter(l => l.cause  === evt.id);

  // IDs of all events involved in this connection web
  const causeIds  = new Set(causeLinks.map(l => l.cause));
  const effectIds = new Set(effectLinks.map(l => l.effect));
  const allConnected = new Set([...causeIds, ...effectIds, evt.id]);

  // ── 1. Dim every marker that isn't part of this connection ────────────────
  for (const [id, layer] of activeLayers) {
    const connected = allConnected.has(id);
    if (layer.circle) layer.circle.setStyle(connected
      ? { opacity: 0.95, fillOpacity: 0.18, weight: 2 }
      : { opacity: 0.07, fillOpacity: 0.02, weight: 1 });
    if (layer.marker) layer.marker.setOpacity(connected ? 1 : 0.07);
  }

  // ── 2. Selected event gets a bright white ring ────────────────────────────
  const selLayer = activeLayers.get(evt.id);
  const selColor = DOT_COLORS[evt.color]?.dot || '#ffffff';
  if (selLayer?.circle) {
    selLayer.circle.setStyle({
      opacity: 1, fillOpacity: 0.3, weight: 3,
      color: '#ffffff', fillColor: selColor,
    });
  }

  // ── 3. Bounds collection — always include the selected event ──────────────
  const boundsPts = [[evt.lat, evt.lon]];

  // ── 4. Draw dashed orange lines from each cause → selected event ──────────
  for (const link of causeLinks) {
    if (!link?.cause) continue;
    const src = EVENTS_BY_ID.get(link.cause);
    if (!src || src.lat == null) continue;
    boundsPts.push([src.lat, src.lon]);

    // Animated dashed orange line
    const line = L.polyline([[src.lat, src.lon], [evt.lat, evt.lon]], {
      color: '#ff9933', weight: 2.5, opacity: 0.82,
      dashArray: '10, 7', className: 'causal-line-cause', interactive: false,
    }).addTo(map);
    causalLinkLayers.push(line);

    // Tint the cause event's circle orange
    const srcLayer = activeLayers.get(src.id);
    if (srcLayer?.circle) {
      srcLayer.circle.setStyle({
        opacity: 0.92, fillOpacity: 0.22, weight: 2.5,
        color: '#ff9933', fillColor: '#ff9933',
      });
    }
    if (srcLayer?.marker) srcLayer.marker.setOpacity(1);

    // Bold endpoint dot at the cause location
    causalLinkLayers.push(L.circleMarker([src.lat, src.lon], {
      radius: 6, color: '#ff9933', fillColor: '#ff9933',
      fillOpacity: 0.92, weight: 2, interactive: false,
    }).addTo(map));
  }

  // ── 5. Draw dashed teal lines from selected event → each effect ───────────
  for (const link of effectLinks) {
    if (!link?.effect) continue;
    const dst = EVENTS_BY_ID.get(link.effect);
    if (!dst || dst.lat == null) continue;
    boundsPts.push([dst.lat, dst.lon]);

    // Animated dashed teal line
    const line = L.polyline([[evt.lat, evt.lon], [dst.lat, dst.lon]], {
      color: '#33ddaa', weight: 2.5, opacity: 0.82,
      dashArray: '10, 7', className: 'causal-line-effect', interactive: false,
    }).addTo(map);
    causalLinkLayers.push(line);

    // Tint the effect event's circle teal
    const dstLayer = activeLayers.get(dst.id);
    if (dstLayer?.circle) {
      dstLayer.circle.setStyle({
        opacity: 0.92, fillOpacity: 0.22, weight: 2.5,
        color: '#33ddaa', fillColor: '#33ddaa',
      });
    }
    if (dstLayer?.marker) dstLayer.marker.setOpacity(1);

    // Bold endpoint dot at the effect location
    causalLinkLayers.push(L.circleMarker([dst.lat, dst.lon], {
      radius: 6, color: '#33ddaa', fillColor: '#33ddaa',
      fillOpacity: 0.92, weight: 2, interactive: false,
    }).addTo(map));
  }

  // ── 6. Zoom map to fit all connected events (only when >1 point) ──────────
  if (boundsPts.length > 1) {
    map.fitBounds(L.latLngBounds(boundsPts), {
      padding: [90, 90], maxZoom: 5, animate: true, duration: 0.6,
    });
  }

  // ── 7. Highlight global simultaneous events at the selected event's year ───
  highlightSimultaneousEvents(evt.startYear, evt.id);
}

function clearCausalLinks() {
  for (const l of causalLinkLayers) l.remove();
  causalLinkLayers    = [];
  _connectionActiveId = null;
  _simultaneousYear   = null;

  // Restore every active layer to its original event color and full opacity
  for (const [id, layer] of activeLayers) {
    if (layer.circle) layer.circle.setStyle(_baseCircleStyle(id));
    if (layer.marker) layer.marker.setOpacity(1);
    // Clear any leftover sim-glow from the marker element
    layer.marker?.getElement?.()?.classList.remove('sim-glow');
  }

  // Re-apply follow dimming if a follow thread is active
  if (typeof refreshFollowStyling === 'function') refreshFollowStyling();
}

// ─── Simultaneous World Events ────────────────────────────────────────────────
// Shows other events happening at the same point in history, WITHOUT overriding
// the priority-1 (selected) or priority-2 (cause/effect) marker styles.

let _simultaneousYear = null; // last year passed to highlightSimultaneousEvents

function highlightSimultaneousEvents(selectedYear, selectedEventId) {
  // Only run while a connection web is active
  if (!_connectionActiveId) return;
  _simultaneousYear = selectedYear;

  // Build the set of events that already have priority styling (must not touch them)
  const causeIds  = new Set(CAUSAL_LINKS.filter(l => l.effect === selectedEventId).map(l => l.cause));
  const effectIds = new Set(CAUSAL_LINKS.filter(l => l.cause  === selectedEventId).map(l => l.effect));
  const priorityIds = new Set([...causeIds, ...effectIds, selectedEventId]);

  for (const [id, layer] of activeLayers) {
    if (priorityIds.has(id)) continue; // selected / cause / effect — already styled, skip

    const ev = EVENTS_BY_ID.get(id);
    if (!ev) continue;

    const isSim = selectedYear >= ev.startYear && selectedYear <= ev.endYear;

    if (isSim) {
      // Priority 3: subtle but visible — halfway between connected and dimmed
      if (layer.circle) layer.circle.setStyle({ opacity: 0.52, fillOpacity: 0.09, weight: 1.5 });
      if (layer.marker) layer.marker.setOpacity(0.55);
      // Add soft-glow class to the marker icon element
      const el = layer.marker?.getElement?.();
      if (el) el.classList.add('sim-glow');
    }
    // If not simultaneous and not priority, leave at the dimmed style (0.07) already set
  }
}

function addEventLayer(evt) {
  if (!evt.lat && !evt.lon) return;
  const c        = DOT_COLORS[evt.color];
  const imp      = eventImportance(evt.id);
  const px       = _IMP_DOT_PX[imp - 1];
  const isGlobal = (evt.radius || 0) >= GLOBAL_RADIUS_THRESHOLD;

  let circle = null;
  if (isGlobal) {
    // Global-scale event: tint the whole map instead of drawing an outer circle
    activeGlobalColors.set(evt.id, c.dot);
    updateWorldGlow();
  } else {
    circle = L.circle([evt.lat, evt.lon], {
      radius: evt.radius || 100000,
      color: c.dot,
      weight: _IMP_WEIGHT[imp - 1],
      opacity: 0.75,
      fillColor: c.dot,
      fillOpacity: _IMP_FILL_OP[imp - 1],
      interactive: true,
    }).addTo(map);
  }

  const marker = L.marker([evt.lat, evt.lon], {
    icon: makeIcon(c.dot, px),
    zIndexOffset: 1000 + (3 - imp) * 200,  // tier-1 dots render on top
  }).addTo(map);

  const openFn = () => {
    openDetailPanel(evt);
    if (evt.lat != null && evt.lon != null)
      _panForDetail(evt.lat, evt.lon, Math.max(map.getZoom(), 4));
  };
  if (circle) {
    circle.on('click', openFn);
    circle.on('mouseover', () => {
      if (_connectionActiveId) return;
      circle.setStyle({ fillOpacity: 0.26, opacity: 1 });
    });
    circle.on('mouseout', () => {
      if (_connectionActiveId) return;
      circle.setStyle({ fillOpacity: 0.1, opacity: 0.7 });
    });
  }
  marker.on('click', openFn);

  const lines = [];
  if (evt.detail?.movements) {
    for (const m of evt.detail.movements) {
      const line = L.polyline(m.path, {
        color: m.color || c.dot,
        weight: 2,
        opacity: 0.65,
        dashArray: '10, 8',
        className: 'ev-movement',
        interactive: false,
      }).addTo(map);
      lines.push(line);
    }
  }

  activeLayers.set(evt.id, { circle, marker, lines });
}

function removeEventLayer(id) {
  const layers = activeLayers.get(id);
  if (!layers) return;
  if (layers.circle) {
    layers.circle.remove();
  } else {
    // Global event — remove its color contribution from the world glow
    activeGlobalColors.delete(id);
    updateWorldGlow();
  }
  layers.marker.remove();
  layers.lines.forEach(l => l.remove());
  activeLayers.delete(id);
}

function updateActiveLayers(year) {
  const nowActive = new Set(
    EVENTS.filter(e => year >= e.startYear && year <= e.endYear && (e.lat || e.lon)).map(e => e.id)
  );

  for (const id of activeLayers.keys()) {
    if (!nowActive.has(id)) removeEventLayer(id);
  }
  for (const id of nowActive) {
    if (!activeLayers.has(id)) {
      const evt = EVENTS_BY_ID.get(id);
      if (evt) addEventLayer(evt);
    }
  }

  document.getElementById('event-count-num').textContent = activeLayers.size;
}

// ─── Timeline Control ─────────────────────────────────────────────────────────
let playYear  = YEAR_MIN;
let isPlaying = false;
let lastTs    = null;
let stepsPerSecond = 3;   // years per second — 0.5×=1  1×=3  2×=10  ⚡=50

function fmtYearDisplay(y) {
  const abs = Math.abs(Math.round(y));
  return y < 0 ? `${abs} BCE` : `${abs} CE`;
}

function applyYear(year) {
  year = Math.max(YEAR_MIN, Math.min(YEAR_MAX, year));
  updateActiveLayers(year);
  document.getElementById('year-display').textContent = fmtYearDisplay(year);
  document.getElementById('timeline-slider').value = year;
  updateChips(year);
  if (typeof refreshFollowStyling === 'function') refreshFollowStyling();

  // If slider moves while an event is selected, refresh simultaneous events for the new year
  if (_connectionActiveId) {
    highlightSimultaneousEvents(year, _connectionActiveId);
  }

  // Update historical region overlays
  if (typeof updateRegions === 'function') updateRegions(year);

  // Update country evolution panel
  if (typeof updateCountryPanel === 'function') updateCountryPanel(year);
}

function updateChips(year) {
  const list = document.getElementById('events-list');
  const noEv = document.getElementById('no-events');
  const active = EVENTS.filter(e => year >= e.startYear && year <= e.endYear);

  if (!active.length) {
    list.innerHTML = '';
    if (!list.contains(noEv)) list.appendChild(noEv);
    noEv.style.display = '';
    return;
  }

  noEv.style.display = 'none';
  const existing = new Set([...list.querySelectorAll('.event-chip')].map(el => el.dataset.id));
  const incoming = new Set(active.map(e => e.id));

  for (const el of [...list.querySelectorAll('.event-chip')]) {
    if (!incoming.has(el.dataset.id)) el.remove();
  }

  for (const evt of active) {
    if (!existing.has(evt.id)) {
      const c = DOT_COLORS[evt.color];
      const chip = document.createElement('div');
      chip.className = 'event-chip';
      chip.dataset.id = evt.id;
      chip.style.background = c.dot + '18';
      chip.style.border = `1px solid ${c.dot}33`;
      chip.innerHTML = `<div class="event-chip-dot" style="background:${c.dot}"></div>
                        <span style="color:${c.dot}cc;font-size:10.5px">${evt.name}</span>`;
      chip.addEventListener('click', () => {
        openDetailPanel(evt);
        if (evt.lat != null && evt.lon != null)
          _panForDetail(evt.lat, evt.lon, Math.max(map.getZoom(), 4));
        drawCausalLinks(evt);
      });
      list.appendChild(chip);
    }
  }
}

function setPlaying(val) {
  isPlaying = val;
  lastTs = null;
  const btn = document.getElementById('play-btn');
  document.getElementById('play-icon').style.display  = val ? 'none' : '';
  document.getElementById('pause-icon').style.display = val ? '' : 'none';
  btn.classList.toggle('playing', val);
}

function drawFrame(ts) {
  if (isPlaying) {
    if (lastTs !== null) {
      const dt = (ts - lastTs) / 1000;
      playYear += dt * stepsPerSecond;
      if (playYear >= YEAR_MAX) { playYear = YEAR_MAX; setPlaying(false); }
      applyYear(Math.round(playYear));
    }
    lastTs = ts;
  }
  requestAnimationFrame(drawFrame);
}

document.getElementById('play-btn').addEventListener('click', () => {
  if (playYear >= YEAR_MAX) playYear = YEAR_MIN;
  setPlaying(!isPlaying);
});

let _sliderRaf = null;
document.getElementById('timeline-slider').addEventListener('input', (e) => {
  playYear = +e.target.value;
  // Throttle to one applyYear per animation frame — avoids overloading the DOM
  // when the slider is dragged rapidly
  if (_sliderRaf) return;
  _sliderRaf = requestAnimationFrame(() => {
    _sliderRaf = null;
    applyYear(playYear);
  });
});

document.querySelectorAll('.speed-btn').forEach(btn => {
  btn.addEventListener('click', () => {
    document.querySelectorAll('.speed-btn').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');
    stepsPerSecond = +btn.dataset.speed;
  });
});

document.getElementById('reset-btn').addEventListener('click', () => {
  map.setView([22, 12], 2);
});

// ─── Wikipedia API ────────────────────────────────────────────────────────────
const wikiCache = new Map();

async function loadWikiData(title) {
  if (wikiCache.has(title)) return wikiCache.get(title);
  try {
    const url = `https://en.wikipedia.org/api/rest_v1/page/summary/${encodeURIComponent(title)}`;
    const r = await fetch(url);
    if (!r.ok) { wikiCache.set(title, null); return null; }
    const d = await r.json();
    const result = {
      image: d.thumbnail?.source || d.originalimage?.source || null,
      caption: d.description || '',
    };
    wikiCache.set(title, result);
    return result;
  } catch { wikiCache.set(title, null); return null; }
}

// ─── Smart pan: center event dot in the left visible area when detail panel opens ─
// The detail panel is 420px wide on the right, so the left visible area center
// is (window.innerWidth - 420) / 2 from the left edge.
// We shift the map center RIGHT by 210px (half the panel) so the event lands there.
function _panForDetail(lat, lon, zoom) {
  const z   = (zoom != null) ? zoom : map.getZoom();
  const dpW = (window.innerWidth >= 640) ? 420 : 0;
  const evtPt    = map.project([lat, lon], z);
  const centerPt = L.point(evtPt.x + dpW / 2, evtPt.y);
  map.setView(map.unproject(centerPt, z), z, { animate: true, duration: 0.5 });
}

// ─── Detail Panel ─────────────────────────────────────────────────────────────
const detailPanel = document.getElementById('detail-panel');

async function openDetailPanel(evt) {
  const c = DOT_COLORS[evt.color];
  document.getElementById('dp-color-bar').style.background =
    `linear-gradient(90deg, ${c.dot}88 0%, transparent 100%)`;

  const badge = document.getElementById('dp-type-badge');
  badge.textContent = c.label;
  badge.style.cssText = `background:${c.dot}22;color:${c.dot};border:1px solid ${c.dot}44;`;

  document.getElementById('dp-name').textContent        = evt.name;
  document.getElementById('dp-period-text').textContent = evt.period;
  document.getElementById('dp-overview').textContent    = evt.detail?.overview || evt.description;

  // Key people
  const peopleSec = document.getElementById('dp-sec-people');
  const peopleEl  = document.getElementById('dp-people');
  if (evt.detail?.keyPeople?.length) {
    peopleEl.innerHTML = evt.detail.keyPeople.map(p => {
      const name = typeof p === 'string' ? p : p.name;
      const role = (typeof p === 'object' && p.role) ? p.role : '';
      return `<div class="dp-person">
        <div class="dp-person-name">${name}</div>
        ${role ? `<div class="dp-person-role">${role}</div>` : ''}
      </div>`;
    }).join('');
    peopleSec.style.display = '';
  } else peopleSec.style.display = 'none';

  // Causes
  const causesSec = document.getElementById('dp-sec-causes');
  const causesEl  = document.getElementById('dp-causes');
  if (evt.detail?.causes?.length) {
    causesEl.innerHTML = evt.detail.causes.map(c => `<li>${c}</li>`).join('');
    causesSec.style.display = '';
  } else causesSec.style.display = 'none';

  // Event timeline
  const tlSec = document.getElementById('dp-sec-timeline');
  const tlEl  = document.getElementById('dp-timeline');
  if (evt.detail?.eventTimeline?.length) {
    tlEl.innerHTML = evt.detail.eventTimeline.map(t =>
      `<div class="dp-tl-item">
         <div class="dp-tl-date">${t.date}</div>
         <div class="dp-tl-evt">${t.event}</div>
       </div>`).join('');
    tlSec.style.display = '';
  } else tlSec.style.display = 'none';

  // Impact
  const impSec = document.getElementById('dp-sec-impact');
  const impEl  = document.getElementById('dp-impact');
  if (evt.detail?.impact?.length) {
    impEl.innerHTML = evt.detail.impact.map(i => `<li>${i}</li>`).join('');
    impSec.style.display = '';
  } else impSec.style.display = 'none';

  // ── Causal chain: precursors (what caused this) ──
  const precSec  = document.getElementById('dp-sec-precursors');
  const precEl   = document.getElementById('dp-precursors');
  const causedBy = CAUSAL_LINKS
    .filter(l => l.effect === evt.id)
    .map(l => ({ linked: EVENTS.find(e => e.id === l.cause), desc: l.desc }))
    .filter(x => x.linked);
  if (causedBy.length) {
    precEl.innerHTML = causedBy.map(({linked: ce, desc}) => {
      const cc = DOT_COLORS[ce.color];
      return `<div class="dp-causal-chip" data-id="${ce.id}">
        <div class="dp-causal-dot-wrap"><div class="dp-causal-dot" style="background:${cc.dot};box-shadow:0 0 4px ${cc.dot}88"></div></div>
        <div>
          <div class="dp-causal-name">${ce.name}</div>
          <div class="dp-causal-period">${ce.period}</div>
          <div class="dp-causal-desc">${desc}</div>
        </div>
      </div>`;
    }).join('');
    precEl.querySelectorAll('.dp-causal-chip').forEach(chip => {
      chip.addEventListener('click', () => {
        const linked = EVENTS.find(e => e.id === chip.dataset.id);
        if (linked) openDetailPanel(linked);
      });
    });
    precSec.style.display = '';
  } else precSec.style.display = 'none';

  // ── Causal chain: effects (what this led to) ──
  const effSec   = document.getElementById('dp-sec-effects');
  const effEl    = document.getElementById('dp-effects');
  const ledTo    = CAUSAL_LINKS
    .filter(l => l.cause === evt.id)
    .map(l => ({ linked: EVENTS.find(e => e.id === l.effect), desc: l.desc }))
    .filter(x => x.linked);
  if (ledTo.length) {
    effEl.innerHTML = ledTo.map(({linked: de, desc}) => {
      const dc = DOT_COLORS[de.color];
      return `<div class="dp-causal-chip" data-id="${de.id}">
        <div class="dp-causal-dot-wrap"><div class="dp-causal-dot" style="background:${dc.dot};box-shadow:0 0 4px ${dc.dot}88"></div></div>
        <div>
          <div class="dp-causal-name">${de.name}</div>
          <div class="dp-causal-period">${de.period}</div>
          <div class="dp-causal-desc">${desc}</div>
        </div>
      </div>`;
    }).join('');
    effEl.querySelectorAll('.dp-causal-chip').forEach(chip => {
      chip.addEventListener('click', () => {
        const linked = EVENTS.find(e => e.id === chip.dataset.id);
        if (linked) openDetailPanel(linked);
      });
    });
    effSec.style.display = '';
  } else effSec.style.display = 'none';

  // Draw causal link lines on the map
  drawCausalLinks(evt);

  // ── Reset image + video ──────────────────────────────────────────────────────
  const imgEl      = document.getElementById('dp-img');
  const capEl      = document.getElementById('dp-img-caption');
  const loadEl     = document.getElementById('dp-img-loading');
  const videoWrap  = document.getElementById('dp-video-wrap');
  const videoEmbed = document.getElementById('dp-video-embed');
  const videoIframe= document.getElementById('dp-video-iframe');
  const videoLabel = document.getElementById('dp-video-label');
  const videoBtn   = document.getElementById('dp-video-btn');

  if (imgEl)    { imgEl.style.display = 'none'; imgEl.src = ''; imgEl.onerror = null; }
  if (capEl)    { capEl.textContent = ''; }
  if (loadEl)   { loadEl.style.display = 'none'; }
  if (videoWrap)  { videoWrap.style.display = 'none'; }
  if (videoEmbed) { videoEmbed.classList.remove('open'); }
  if (videoIframe){ videoIframe.src = ''; }
  if (videoLabel) { videoLabel.textContent = 'Watch Video'; }
  if (videoBtn)   { videoBtn.onclick = null; }

  detailPanel.classList.add('open');
  document.getElementById('follow-event-strip').classList.add('panel-open');
  document.getElementById('dp-scroll').scrollTop = 0;

  const media = evt.detail?.media || {};

  // ── Direct media image (shown immediately, no API call needed) ───────────────
  if (media.image && imgEl && loadEl) {
    loadEl.style.display = 'none';
    imgEl.onerror = () => { imgEl.style.display = 'none'; };
    imgEl.src = media.image;
    imgEl.style.display = '';
    if (capEl) capEl.textContent = '';
  } else {
    // Fall back to Wikipedia image
    const wiki = evt.detail?.wiki;
    if (wiki && loadEl) {
      loadEl.style.display = '';
      try {
        const data = await loadWikiData(wiki);
        if (loadEl) loadEl.style.display = 'none';
        if (data?.image && imgEl) {
          imgEl.src = data.image;
          imgEl.style.display = '';
          if (capEl) capEl.textContent = data.caption || '';
        }
      } catch { if (loadEl) loadEl.style.display = 'none'; }
    }
  }

  // ── Video button (YouTube embed) ─────────────────────────────────────────────
  if (media.video && videoWrap && videoEmbed && videoIframe && videoBtn) {
    videoWrap.style.display = '';
    videoBtn.onclick = () => {
      const open = videoEmbed.classList.toggle('open');
      if (open) {
        videoIframe.src = media.video;
        if (videoLabel) videoLabel.textContent = 'Hide Video';
      } else {
        videoIframe.src = '';
        if (videoLabel) videoLabel.textContent = 'Watch Video';
      }
    };
  }
}

function closeDetailPanel() {
  detailPanel.classList.remove('open');
  document.getElementById('follow-event-strip').classList.remove('panel-open');
  // Stop any playing video to silence audio after panel closes
  const iframe = document.getElementById('dp-video-iframe');
  if (iframe) iframe.src = '';
  const embed = document.getElementById('dp-video-embed');
  if (embed) embed.classList.remove('open');
  clearCausalLinks();
}

document.getElementById('dp-close').addEventListener('click', closeDetailPanel);

// ─── Events Browser Panel ─────────────────────────────────────────────────────
const browseBtn     = document.getElementById('browse-btn');
const eventsOverlay = document.getElementById('events-overlay');
const epClose       = document.getElementById('ep-close');
const epSearch      = document.getElementById('ep-search');
const epList        = document.getElementById('ep-list');
const epNoResults   = document.getElementById('ep-no-results');

const ERAS = [
  { name:"Ancient World",  from:-4000, to:-500  },
  { name:"Classical Era",  from:-500,  to:500   },
  { name:"Medieval",       from:500,   to:1500  },
  { name:"Early Modern",   from:1500,  to:1800  },
  { name:"19th Century",   from:1800,  to:1914  },
  { name:"World Wars Era", from:1914,  to:1945  },
  { name:"Cold War Era",   from:1945,  to:1991  },
  { name:"Modern Era",     from:1991,  to:2026  },
];

let epItems = [];

function buildEventsPanel() {
  const sorted = [...EVENTS].sort((a, b) => a.startYear - b.startYear);

  for (const era of ERAS) {
    const eraEvts = sorted.filter(e => e.startYear >= era.from && e.startYear < era.to);
    if (!eraEvts.length) continue;

    const hdr = document.createElement('div');
    hdr.className = 'ep-era-hdr';
    hdr.textContent = `${era.name} · ${eraEvts.length} events`;
    epList.insertBefore(hdr, epNoResults);

    for (const evt of eraEvts) {
      const c = DOT_COLORS[evt.color];
      const el = document.createElement('div');
      el.className = 'ep-item';
      el.innerHTML = `
        <div class="ep-dot" style="background:${c.dot};box-shadow:0 0 5px ${c.dot}88"></div>
        <div>
          <div class="ep-name">${evt.name}</div>
          <div class="ep-period">${fmtYear(evt.startYear)} &nbsp;·&nbsp; ${c.label}</div>
        </div>`;
      el.addEventListener('click', () => jumpToEvent(evt));
      epList.insertBefore(el, epNoResults);
      epItems.push({
        el, hdr,
        searchText: `${evt.name} ${evt.period} ${evt.description} ${era.name}`.toLowerCase(),
      });
    }
  }
}

function filterEvents(q) {
  const query = q.toLowerCase().trim();
  const hdrVis = new Map();

  for (const item of epItems) {
    const show = !query || item.searchText.includes(query);
    item.el.style.display = show ? '' : 'none';
    if (!hdrVis.has(item.hdr)) hdrVis.set(item.hdr, false);
    if (show) hdrVis.set(item.hdr, true);
  }

  let any = false;
  for (const [hdr, vis] of hdrVis) {
    hdr.style.display = vis ? '' : 'none';
    if (vis) any = true;
  }
  epNoResults.style.display = any ? 'none' : 'block';
}

function jumpToEvent(evt) {
  closeEventsPanel();
  setPlaying(false);
  playYear = evt.startYear;
  applyYear(evt.startYear);
  if (evt.lat || evt.lon) {
    _panForDetail(evt.lat, evt.lon, Math.min(map.getZoom() + 2, 6));
  }
  setTimeout(() => openDetailPanel(evt), 350);
}

function openEventsPanel() {
  eventsOverlay.classList.add('open');
  epSearch.value = '';
  filterEvents('');
  setTimeout(() => epSearch.focus(), 120);
}

function closeEventsPanel() {
  eventsOverlay.classList.remove('open');
}

browseBtn.addEventListener('click', openEventsPanel);
epClose.addEventListener('click', closeEventsPanel);
eventsOverlay.addEventListener('click', e => { if (e.target === eventsOverlay) closeEventsPanel(); });
epSearch.addEventListener('input', e => filterEvents(e.target.value));
document.addEventListener('keydown', e => {
  if (e.key === 'Escape') { closeEventsPanel(); closeDetailPanel(); closeFollowOverlay(); }
});

