// ─── Region state tracking ─────────────────────────────────────────────────────
// _phaseState[id] = { phaseKey: "id:phaseIndex", layers: L.Polygon[], removeTimer }
const _phaseState = {};

const _FADE_IN_MS  = 450;
const _FADE_OUT_MS = 320;

function _getPhase(region, year) {
  const idx = region.phases.findIndex(p => year >= p.start && year <= p.end);
  return idx === -1 ? null : { idx, phase: region.phases[idx] };
}

function _setLayerOpacity(layers, opacity, transMs) {
  const trans = transMs > 0 ? `opacity ${transMs}ms ease` : 'none';
  layers.forEach(l => {
    if (l instanceof L.GeoJSON) {
      // L.GeoJSON is a layer group — reach each sub-layer's SVG path
      l.eachLayer(sub => {
        const el = sub.getElement?.();
        if (el) { el.style.transition = trans; el.style.opacity = String(opacity); }
      });
    } else {
      const el = l.getElement?.();
      if (el) { el.style.transition = trans; el.style.opacity = String(opacity); }
      // Legacy polygon tooltip
      const tt = l.getTooltip?.();
      if (tt) {
        const ttEl = tt.getElement?.();
        if (ttEl) { ttEl.style.transition = trans; ttEl.style.opacity = String(opacity); }
      }
    }
  });
}

function _buildLayers(region, phase, showLabel) {
  const layers = [];

  if (phase.geojson) {
    // ── GeoJSON path — accurate geographic boundaries ──────────────────────
    const geoLayer = L.geoJSON(
      { type: 'Feature', geometry: phase.geojson },
      {
        pane: 'regions',
        style: {
          color:       region.color,
          weight:      2.5,
          opacity:     0.9,
          fillColor:   region.color,
          fillOpacity: 0.13,
          interactive: false,
        },
      }
    ).addTo(historicalLayer);
    layers.push(geoLayer);

    if (showLabel) {
      // phase.label is [lat, lon]; fall back to bounds center
      const center = phase.label
        ? L.latLng(phase.label[0], phase.label[1])
        : geoLayer.getBounds().getCenter();
      const mk = L.marker(center, {
        icon: L.divIcon({
          className:  'region-label',
          html:       region.name,
          iconAnchor: [40, 9],
        }),
        interactive: false,
        pane:        'regions',
      }).addTo(historicalLayer);
      layers.push(mk);
    }
  } else {
    // ── Legacy coord-array path (all other regions unchanged) ──────────────
    const poly = L.polygon(phase.coords, {
      pane:        'regions',
      color:       region.color,
      weight:      2.5,
      opacity:     0.8,
      fillColor:   region.color,
      fillOpacity: 0.22,
      interactive: false,
    });
    if (showLabel) {
      poly.bindTooltip(region.name, {
        permanent: true, direction: 'center',
        className: 'region-label', opacity: 1, interactive: false,
      });
      poly.addTo(historicalLayer).openTooltip();
    } else {
      poly.addTo(historicalLayer);
    }
    layers.push(poly);
  }

  return layers;
}

function _fadeOutAndRemove(layers) {
  // Start the SVG opacity transition to 0
  requestAnimationFrame(() => _setLayerOpacity(layers, 0, _FADE_OUT_MS));
  // After transition finishes, remove from map
  return setTimeout(() => {
    layers.forEach(l => { try { historicalLayer.removeLayer(l); } catch {} });
  }, _FADE_OUT_MS + 50);
}

function _fadeIn(layers) {
  // Layers just added — SVG elements might not be rendered yet; need 2 rAFs
  _setLayerOpacity(layers, 0, 0);   // start invisible (no transition yet)
  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      _setLayerOpacity(layers, 1, _FADE_IN_MS);
    });
  });
}

function updateRegions(year) {
  for (const region of PHASE_REGIONS) {
    const result  = _getPhase(region, year);
    const state   = _phaseState[region.id];
    const newKey  = result ? `${region.id}:${result.idx}` : null;
    const currKey = state ? state.phaseKey : null;

    if (newKey === currKey) continue;   // Phase unchanged — nothing to do

    // ── Immediately remove current layers ─────────────────────────────────
    // Immediate removal prevents ghosted (invisible but present) layers when
    // the user scrubs the slider fast across multiple phase boundaries.
    if (state) {
      if (state.removeTimer) clearTimeout(state.removeTimer);
      state.layers.forEach(l => { try { historicalLayer.removeLayer(l); } catch {} });
      delete _phaseState[region.id];
    }

    // ── Fade in new phase layers ──────────────────────────────────────────
    if (result) {
      const layers = _buildLayers(region, result.phase, true);
      _fadeIn(layers);
      _phaseState[region.id] = { phaseKey: newKey, layers, removeTimer: null };
    }
  }
}

