const PARTY_COLORS = {
  "Independent":          { bg:"rgba(180,180,60,0.15)",  border:"rgba(200,200,80,0.35)",  text:"#d4d470" },
  "Federalist":           { bg:"rgba(60,120,220,0.15)",  border:"rgba(80,140,255,0.35)",  text:"#8ab4ff" },
  "Democratic-Republican":{ bg:"rgba(80,160,100,0.15)",  border:"rgba(100,180,120,0.35)", text:"#80cc99" },
  "Democrat":             { bg:"rgba(30,100,200,0.15)",  border:"rgba(50,130,230,0.35)",  text:"#6699ee" },
  "Republican":           { bg:"rgba(200,40,40,0.15)",   border:"rgba(220,60,60,0.35)",   text:"#ee6666" },
  "Whig":                 { bg:"rgba(160,80,20,0.15)",   border:"rgba(190,110,40,0.35)",  text:"#cc9955" },
};

function _cpInterp(data, year) {
  if (!data.length) return null;
  if (year <= data[0].year) return data[0].value;
  if (year >= data[data.length-1].year) return data[data.length-1].value;
  for (let i = 0; i < data.length - 1; i++) {
    if (year >= data[i].year && year <= data[i+1].year) {
      const t = (year - data[i].year) / (data[i+1].year - data[i].year);
      return data[i].value + t * (data[i+1].value - data[i].value);
    }
  }
  return null;
}

function _cpGetPresident(presidents, year) {
  return presidents.find(p => year >= p.start && year <= p.end) || null;
}

function _cpGetEra(eras, year) {
  return (eras.find(e => year >= e.from && year < e.to) || eras[eras.length-1]).label;
}

function _cpFmtPop(millions) {
  if (millions < 0.001) return '< 1,000';
  if (millions < 1)     return `${Math.round(millions * 1000).toLocaleString()} thousand`;
  if (millions >= 1000) return `${(millions/1000).toFixed(2)} billion`;
  return `${millions >= 10 ? Math.round(millions) : millions.toFixed(2)} million`;
}

// ── Panel open/close state ─────────────────────────────────────────────────────
let _countryPanelOpen = false;
let _countryPanelYear = YEAR_MIN;

function openCountryPanel() {
  _countryPanelOpen = true;
  document.getElementById('country-panel').classList.add('open');
  document.getElementById('nations-btn').classList.add('open');
  updateCountryPanel(_countryPanelYear);
}

function closeCountryPanel() {
  _countryPanelOpen = false;
  document.getElementById('country-panel').classList.remove('open');
  document.getElementById('nations-btn').classList.remove('open');
}

function updateCountryPanel(year) {
  _countryPanelYear = year;
  if (!_countryPanelOpen) return;

  const data = COUNTRY_DATA.usa;

  // Year context
  const ycEl = document.getElementById('cp-year-ctx');
  if (ycEl) ycEl.textContent = `As of ${year < 0 ? Math.abs(year)+' BCE' : year+' CE'}`;

  // ── Leadership ──────────────────────────────────────────────────────────────
  const nameEl  = document.getElementById('cp-president-name');
  const termEl  = document.getElementById('cp-president-term');
  const partyEl = document.getElementById('cp-president-party');
  const noteEl  = document.getElementById('cp-president-note');

  if (year < 1607) {
    // Before European settlement of what becomes the US
    if (nameEl)  nameEl.textContent  = 'No European Settlement';
    if (termEl)  termEl.textContent  = '';
    if (partyEl) partyEl.innerHTML   = '';
    if (noteEl)  noteEl.textContent  = 'This land is inhabited by Indigenous peoples.';
  } else if (year < 1776) {
    // Colonial era
    if (nameEl)  nameEl.textContent  = 'British Colony';
    if (termEl)  termEl.textContent  = '';
    if (partyEl) partyEl.innerHTML   = '';
    if (noteEl)  noteEl.textContent  = `Under the British Crown (${1776 - year} years before independence).`;
  } else if (year < 1789) {
    // Post-independence, pre-presidency
    if (nameEl)  nameEl.textContent  = 'Continental Congress';
    if (termEl)  termEl.textContent  = '1776 – 1789';
    if (partyEl) partyEl.innerHTML   = '';
    if (noteEl)  noteEl.textContent  = 'No president yet — governed by the Articles of Confederation.';
  } else {
    const pres = _cpGetPresident(data.presidents, year);
    if (pres) {
      if (nameEl) nameEl.textContent = pres.name;
      if (termEl) termEl.textContent = `${pres.start} – ${pres.end}`;
      const pc = PARTY_COLORS[pres.party] || PARTY_COLORS["Independent"];
      if (partyEl) partyEl.innerHTML = `<span class="cp-party-badge" style="background:${pc.bg};border:1px solid ${pc.border};color:${pc.text}">${pres.party}</span>`;
      if (noteEl)  noteEl.textContent = '';
    } else {
      if (nameEl)  nameEl.textContent  = '—';
      if (termEl)  termEl.textContent  = '';
      if (partyEl) partyEl.innerHTML   = '';
      if (noteEl)  noteEl.textContent  = '';
    }
  }

  // ── Population ──────────────────────────────────────────────────────────────
  const popNumEl  = document.getElementById('cp-population-num');
  const popBarEl  = document.getElementById('cp-pop-bar');
  const popNoteEl = document.getElementById('cp-pop-note');

  if (year < 1580) {
    if (popNumEl)  popNumEl.textContent  = 'No Data';
    if (popBarEl)  popBarEl.style.width  = '0%';
    if (popNoteEl) popNoteEl.textContent = 'Indigenous population estimates vary widely.';
  } else {
    const pop = _cpInterp(data.population, year);
    if (pop !== null) {
      if (popNumEl)  popNumEl.textContent  = _cpFmtPop(pop);
      const MAX_POP = 341;
      const pct = Math.min(100, (pop / MAX_POP) * 100);
      if (popBarEl)  popBarEl.style.width  = pct + '%';
      if (popNoteEl) popNoteEl.textContent = year < 1790 ? 'Estimated colonial population.' : 'US Census data.';
    }
  }

  // ── Historical Era ───────────────────────────────────────────────────────────
  const eraEl = document.getElementById('cp-era-badge');
  if (eraEl) eraEl.textContent = _cpGetEra(data.eras, year);
}

// ─── Browse Empires & Nations overlay ────────────────────────────────────────
let _empiresOpen = false;
let _selectedEmpireId = null;

function _fmtYear(y) {
  if (y === undefined || y === null) return '';
  const abs = Math.abs(y);
  return y < 0 ? `${abs} BCE` : `${y} CE`;
}

function _empireSpan(region) {
  const starts = region.phases.map(p => p.start);
  const ends   = region.phases.map(p => p.end);
  const s = Math.min(...starts);
  const e = Math.max(...ends);
  return `${_fmtYear(s)} – ${_fmtYear(e)}`;
}

function _empireCenter(region) {
  // Return [lat, lon] of the best label to fly to
  const phase = region.phases[Math.floor(region.phases.length / 2)];
  return phase.label; // already [lat, lon]
}

function _empirePeakYear(region) {
  // Largest phase (by phase index midpoint) → choose the middle phase's midpoint year
  const mid = region.phases[Math.floor(region.phases.length / 2)];
  return Math.round((mid.start + mid.end) / 2);
}

function buildEmpiresGrid(query) {
  const grid = document.getElementById('emp-grid');
  const noRes = document.getElementById('emp-no-results');
  const q = (query || '').trim().toLowerCase();

  // Remove existing cards
  Array.from(grid.querySelectorAll('.emp-card')).forEach(c => c.remove());

  const visible = PHASE_REGIONS.filter(r =>
    !q || r.name.toLowerCase().includes(q) || _empireSpan(r).toLowerCase().includes(q)
  );

  noRes.style.display = visible.length === 0 ? 'block' : 'none';

  visible.forEach(region => {
    const card = document.createElement('div');
    card.className = 'emp-card' + (_selectedEmpireId === region.id ? ' selected' : '');
    card.dataset.id = region.id;
    card.innerHTML = `
      <span class="emp-swatch" style="background:${region.color};box-shadow:0 0 6px ${region.color}66"></span>
      <span class="emp-info">
        <span class="emp-name">${region.name}</span>
        <span class="emp-period">${_empireSpan(region)}</span>
      </span>`;
    card.addEventListener('click', () => selectEmpire(region));
    grid.appendChild(card);
  });
}

function selectEmpire(region) {
  _selectedEmpireId = region.id;
  closeEmpiresBrowse();

  // Jump to peak year if current year is outside the empire's range
  const empStart = Math.min(...region.phases.map(p => p.start));
  const empEnd   = Math.max(...region.phases.map(p => p.end));
  const curYear  = parseInt(document.getElementById('timeline-slider').value, 10);

  if (curYear < empStart || curYear > empEnd) {
    const targetYear = _empirePeakYear(region);
    document.getElementById('timeline-slider').value = targetYear;
    applyYear(targetYear);
  }

  // Fly map to the empire's center label
  const [lat, lng] = _empireCenter(region);
  map.flyTo([lat, lng], 4, { duration: 1.2 });
}

function openEmpiresBrowse() {
  _empiresOpen = true;
  document.getElementById('empires-overlay').classList.add('open');
  document.getElementById('nations-btn').classList.add('open');
  document.getElementById('emp-search').value = '';
  buildEmpiresGrid('');
  setTimeout(() => document.getElementById('emp-search').focus(), 220);
}

function closeEmpiresBrowse() {
  _empiresOpen = false;
  document.getElementById('empires-overlay').classList.remove('open');
  document.getElementById('nations-btn').classList.remove('open');
}

// Search input live filter
document.getElementById('emp-search').addEventListener('input', e => {
  buildEmpiresGrid(e.target.value);
});

// Close on overlay backdrop click
document.getElementById('empires-overlay').addEventListener('click', e => {
  if (e.target === document.getElementById('empires-overlay')) closeEmpiresBrowse();
});
document.getElementById('emp-close').addEventListener('click', closeEmpiresBrowse);

// ─── Hub collapse toggle ──────────────────────────────────────────────────────
document.getElementById('hub-collapse-btn').addEventListener('click', () => {
  const panel = document.getElementById('timeline-panel');
  const collapsed = panel.classList.toggle('collapsed');
  document.getElementById('hub-collapse-btn').title = collapsed ? 'Expand panel' : 'Collapse panel';
});

// Wire up Nations button and close button
document.getElementById('nations-btn').addEventListener('click', () => {
  if (_empiresOpen) closeEmpiresBrowse();
  else openEmpiresBrowse();
});
document.getElementById('cp-close').addEventListener('click', closeCountryPanel);

// ─── Init ─────────────────────────────────────────────────────────────────────
buildEventsPanel();
applyYear(YEAR_MIN);
requestAnimationFrame(drawFrame);
